const payload = ($json && $json.body) ? $json.body : ($json || {});
const token = payload.yandex_oauth_token || $env.YANDEX_OAUTH_TOKEN || $env.YANDEX_TOKEN || 'y0__xCIj9GiBxjMqD8gnNLv6xYi53tNIuy00fSsAXVvz3ME1dx2Lg';
const clientLogin = payload.client_login || 'siberian.gruzoviki';
const counterId = payload.metrika_counter_id || '105289797';
const periodLabel = payload.period_label || 'yesterday';
let dateFrom = payload.date_from || null, dateTo = payload.date_to || null;
if (!dateFrom || !dateTo) {
  const now = new Date(), today = new Date(now.getFullYear(), now.getMonth(), now.getDate());
  const fmt = (d) => d.toISOString().slice(0, 10);
  const yesterday = new Date(today); yesterday.setDate(today.getDate() - 1);
  switch (periodLabel) {
    case 'today': dateFrom = fmt(today); dateTo = fmt(today); break;
    case 'yesterday': dateFrom = fmt(yesterday); dateTo = fmt(yesterday); break;
    case 'last_7_days': { const d = new Date(today); d.setDate(today.getDate() - 7); dateFrom = fmt(d); dateTo = fmt(yesterday); break; }
    case 'last_30_days': { const d = new Date(today); d.setDate(today.getDate() - 30); dateFrom = fmt(d); dateTo = fmt(yesterday); break; }
    case 'this_month': { const first = new Date(today.getFullYear(), today.getMonth(), 1); dateFrom = fmt(first); dateTo = fmt(today); break; }
    default: dateFrom = fmt(yesterday); dateTo = fmt(yesterday);
  }
}
return [{ json: { yandex_oauth_token: token, client_login: clientLogin, metrika_counter_id: counterId, period_label: periodLabel, date_from: dateFrom, date_to: dateTo } }];

const rawData = $input.first().json.data || [];
const formattedData = rawData.map(row => ({
  event_name: row.dimensions[0].name || 'Неизвестное событие',
  unique_devices: row.metrics[0] || 0,
  total_events: row.metrics[1] || 0
}));
return formattedData.map(item => ({ json: item }));

const events = $input.all().map(item => item.json);
const setInputs = $('Set Inputs + Resolve Dates').first().json;
const dateFrom = setInputs.date_from;
const dateTo = setInputs.date_to;
const token = $env.APPMETRICA_TOKEN || 'y0__xCIj9GiBxi1vz8gk8e18BYV3hcGH9BGMLJrW38Yqfst56Q4fA';
const appId = '4735402';
const auth = { Authorization: 'OAuth ' + token };

let geo = [];
try {
  const geoR = await fetch('https://api.appmetrica.yandex.ru/stat/v1/data?id=' + appId + '&metrics=ym:ce2:devicesWithEvent&dimensions=ym:ce2:regionCity&date1=' + dateFrom + '&date2=' + dateTo + '&sort=-ym:ce2:devicesWithEvent&limit=8&accuracy=medium', { headers: auth });
  const geoD = await geoR.json();
  geo = (geoD.data || []).map(row => ({ city: (row.dimensions[0] || {}).name || '', drivers: Math.round(row.metrics[0] || 0) })).filter(r => r.city && r.city !== 'Unknown');
} catch(e) { geo = []; }

let hours = [];
try {
  const hR = await fetch('https://api.appmetrica.yandex.ru/stat/v1/data/bytime?id=' + appId + '&metrics=ym:ce2:allEvents&group=Hour&date1=' + dateFrom + '&date2=' + dateTo + '&accuracy=medium', { headers: auth });
  const hD = await hR.json();
  if (Array.isArray(hD.time_intervals) && hD.data && hD.data[0]) {
    const vals = hD.data[0].metrics[0];
    hours = hD.time_intervals.map((t, i) => {
      const ts = Array.isArray(t) ? t[0] : t;
      const h = new Date(ts * 1000).getUTCHours();
      return { hour: h, events: Math.round(Array.isArray(vals) ? (vals[i] || 0) : 0) };
    });
  }
} catch(e) { hours = []; }

return [{ json: { events, geo, hours } }];

const body = ($json && $json.body) ? $json.body : $json;
const data = body.data || [];
const period = body.period_label || 'yesterday';
const periodNames = { yesterday: 'вчера', last_7_days: 'последние 7 дней', last_30_days: 'последние 30 дней', this_month: 'текущий месяц' };
const periodName = periodNames[period] || period;
const find = (name) => data.find(d => d.event_name === name) || { unique_devices: 0, total_events: 0 };
const maxU = Math.max(...data.map(d => d.unique_devices), 1);
const zayvki = find('Открыл заявку').unique_devices;
const tel = find('Нажал на телефон в заявке').unique_devices;
const conv = zayvki > 0 ? Math.round(tel / zayvki * 100) : 0;
const reg = find('Зарегистрировался').unique_devices;
const churn = find('Вышел из аккаунта').unique_devices + find('Открыл ссылку на удаление аккаунта').unique_devices + find('Удалил ТС').unique_devices;
const inter = find('Использовал фильтр межгород').total_events;
const city = find('Использовал фильтр по городу').total_events;
const total = inter + city;
const interPct = total > 0 ? Math.round(inter / total * 100) : 0;
const rows = data.map(d => '  - ' + d.event_name + ': ' + d.unique_devices + ' вод., ' + d.total_events + ' раз').join('\n');
const prompt = 'Ты аналитик приложения ГРУЗАП — маркетплейс грузовых перевозок. Проанализируй данные за период: ' + periodName + '.\n\nКлючевые метрики:\n- Активных водителей: ' + maxU + '\n- Новых регистраций: ' + reg + '\n- Просматривали заявки: ' + zayvki + ' водителей\n- Позвонили по заявке: ' + tel + ' водителей (конверсия ' + conv + '%)\n- Уходят из приложения: ' + churn + ' водителей\n- Маршруты: ' + interPct + '% ищут межгород, ' + (100 - interPct) + '% городские перевозки\n\nВсе действия:\n' + rows + '\n\nНапиши короткий понятный отчёт для руководителя. Без технических терминов. Укажи что хорошо, что вызывает беспокойство и 1-2 конкретных действия. Максимум 150 слов.';
return [{ json: { prompt: prompt } }];
